// isKnownInterval reports whether v matches one of the enum values rendered
// by the check-interval <select>. When the persisted CheckIntervalHours is
// outside this set (e.g., set via direct API call to a custom cadence), the
// template renders a sentinel "(custom)" option so a Save without explicit
// interval change does not silently overwrite the persisted value with the
// browser's first-option fallback.
func isKnownInterval(v int) bool {
	switch v {
	case 1, 6, 12, 24, 168:
		return true
	default:
		return false
	}
}

